{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/WrappingRuleReproductionTest.kt","content":"package com.pinterest.ktlint.ruleset.standard

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.MULTILINE_STRING_QUOTE
import org.junit.jupiter.api.Test

internal class WrappingRuleReproductionTest {
    private val wrappingRuleAssertThat = assertThatRule { WrappingRule() }

    @Test
    fun `Issue 1774 - wrapping raw string false positive Missing newline after {`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                                   $EOL_CHAR
            package test

            class QueryGenerator {
                fun getQueryString(query: QueryRequest): String {
                    val q = $MULTILINE_STRING_QUOTE
                        SELECT *
                        FROM table_name_long_enough_so_max_line_length_is_met_and_wrapping_rule_is_violated
                        WHERE 1 = 1
                        ${"$"}{query.gameId?.let { "AND id = ?" } ?: ""}    
                    $MULTILINE_STRING_QUOTE
                    return q
                }
            }

            data class QueryRequest(
                val gameId: String?,
            )
            """.trimIndent()
        wrappingRuleAssertThat(code)
            .setMaxLineLength()
            .hasNoLintViolations()
    }
}
"}

