277→public fun ASTNode.upsertWhitespaceBeforeMe(text: String) {
278→    if (this is LeafElement) {
279→        if (this.elementType == WHITE_SPACE) {
280→            return replaceWhitespaceWith(text)
281→        }
282→        val previous = treePrev ?: prevLeaf()
283→        if (previous != null && previous.elementType == WHITE_SPACE) {
284→            previous.replaceWhitespaceWith(text)
285→        } else {
286→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
287→                (psi as LeafElement).rawInsertBeforeMe(psiWhiteSpace)
288→            }
289→        }
290→    } else {
291→        val prevLeaf =
292→            requireNotNull(prevLeaf()) {
293→                "Can not upsert a whitespace if the first node is a non-leaf node"
294→            }
295→        prevLeaf.upsertWhitespaceAfterMe(text)
296→    }
297→}
