308→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
309→ * added after the last child leaf.
310→ */
311→public fun ASTNode.upsertWhitespaceAfterMe(text: String) {
312→    if (this is LeafElement) {
313→        if (this.elementType == WHITE_SPACE) {
314→            return replaceWhitespaceWith(text)
315→        }
316→        val next = treeNext ?: nextLeaf()
317→        if (next != null && next.elementType == WHITE_SPACE) {
318→            next.replaceWhitespaceWith(text)
319→        } else {
320→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
321→                (psi as LeafElement).rawInsertAfterMe(psiWhiteSpace)
322→            }
323→        }
324→    } else {
